package am.froshy.launcher.api.internal;

import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.LauncherUpdateStatus;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.List;
import java.util.Map;

public final class InternalApiClient {
    private final URI baseUri;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public InternalApiClient(URI baseUri) {
        String normalizedBase = baseUri.toString().endsWith("/") ? baseUri.toString() : baseUri + "/";
        this.baseUri = URI.create(normalizedBase);
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public Map<String, Object> health() {
        return send("health", "GET", null, new TypeReference<>() {});
    }

    public List<MinecraftProfile> listProfiles() {
        return send("profiles", "GET", null, new TypeReference<>() {});
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        return send("profiles", "POST", profile, new TypeReference<>() {});
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile profile) {
        return send("profiles/" + existingId, "PUT", profile, new TypeReference<>() {});
    }

    public String getProfileInstancePath(String profileId) {
        Map<String, Object> response = send("profiles/" + profileId + "/instance-path", "GET", null, new TypeReference<>() {});
        Object instancePath = response.get("instancePath");
        return instancePath == null ? "" : instancePath.toString();
    }

    public LaunchResult launch(LaunchRequest request) {
        return send("launch", "POST", request, new TypeReference<>() {});
    }

    public LaunchResult launchPrepared(LaunchRequest request) {
        return send("launch-prepared", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus startLaunchPreparedAsync(LaunchRequest request) {
        return send("launch-prepared/start", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus getLaunchPreparedStatus(String operationId) {
        return send("launch-prepared/" + operationId, "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus startDownload(String target) {
        return send("downloads", "POST", Map.of("target", target), new TypeReference<>() {});
    }

    public DownloadStatus getDownloadStatus(String downloadId) {
        return send("downloads/" + downloadId, "GET", null, new TypeReference<>() {});
    }

    public LauncherUpdateStatus checkUpdates() {
        return send("updates/check", "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus prepareVersion(String version) {
        return send("versions/prepare", "POST", Map.of("version", version), new TypeReference<>() {});
    }

    public String getModpackCompatibilityMode() {
        Map<String, Object> response = send("settings/modpack-compat", "GET", null, new TypeReference<>() {});
        Object mode = response.get("mode");
        return mode == null ? "BOTH" : mode.toString();
    }

    public String setModpackCompatibilityMode(String mode) {
        Map<String, Object> response = send("settings/modpack-compat", "POST", Map.of("mode", mode), new TypeReference<>() {});
        Object applied = response.get("mode");
        return applied == null ? "BOTH" : applied.toString();
    }

    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        return send("launch/" + launchId + "/output?from=" + fromIndex, "GET", null, new TypeReference<>() {});
    }

    public boolean isGameAlive(String launchId) {
        Map<String, Object> res = send("launch/" + launchId + "/alive", "GET", null, new TypeReference<>() {});
        return Boolean.TRUE.equals(res.get("alive"));
    }

    private <T> T send(String path, String method, Object body, TypeReference<T> typeReference) {
        try {
            HttpRequest request = buildRequest(path, method, body);
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() >= 400) {
                throw new IllegalStateException("Error API " + response.statusCode() + ": " + response.body());
            }
            return objectMapper.readValue(response.body(), typeReference);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo parsear la respuesta", ex);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("Llamada interrumpida", ex);
        }
    }

    private HttpRequest buildRequest(String path, String method, Object body) throws IOException {
        HttpRequest.Builder builder = HttpRequest.newBuilder()
                .uri(baseUri.resolve(path))
                .timeout(Duration.ofSeconds(10))
                .header("Content-Type", "application/json");

        if ("GET".equalsIgnoreCase(method)) {
            return builder.GET().build();
        }

        byte[] payload = objectMapper.writeValueAsBytes(body);
        return builder.method(method, HttpRequest.BodyPublishers.ofByteArray(payload)).build();
    }
}

package am.froshy.launcher.api.internal;

import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.LauncherUpdateStatus;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.List;
import java.util.Map;

public final class InternalApiClient {
    private final URI baseUri;
    private final HttpClient httpClient;
    private final ObjectMapper objectMapper;

    public InternalApiClient(URI baseUri) {
        String normalizedBase = baseUri.toString().endsWith("/") ? baseUri.toString() : baseUri + "/";
        this.baseUri = URI.create(normalizedBase);
        this.httpClient = HttpClient.newBuilder()
                .connectTimeout(Duration.ofSeconds(3))
                .build();
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
    }

    public Map<String, Object> health() {
        return send("health", "GET", null, new TypeReference<>() {});
    }

    public List<MinecraftProfile> listProfiles() {
        return send("profiles", "GET", null, new TypeReference<>() {});
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        return send("profiles", "POST", profile, new TypeReference<>() {});
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile profile) {
        return send("profiles/" + existingId, "PUT", profile, new TypeReference<>() {});
    }

    public void deleteProfile(String profileId) {
        send("profiles/" + profileId, "DELETE", null, new TypeReference<Map<String, Object>>() {});
    }

    public String getProfileInstancePath(String profileId) {
        Map<String, Object> response = send("profiles/" + profileId + "/instance-path", "GET", null, new TypeReference<>() {});
        Object instancePath = response.get("instancePath");
        return instancePath == null ? "" : instancePath.toString();
    }

    public LaunchResult launch(LaunchRequest request) {
        return send("launch", "POST", request, new TypeReference<>() {});
    }

    public LaunchResult launchPrepared(LaunchRequest request) {
        return send("launch-prepared", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus startLaunchPreparedAsync(LaunchRequest request) {
        return send("launch-prepared/start", "POST", request, new TypeReference<>() {});
    }

    public PreparedLaunchStatus getLaunchPreparedStatus(String operationId) {
        return send("launch-prepared/" + operationId, "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus startDownload(String target) {
        return send("downloads", "POST", Map.of("target", target), new TypeReference<>() {});
    }

    public DownloadStatus getDownloadStatus(String downloadId) {
        return send("downloads/" + downloadId, "GET", null, new TypeReference<>() {});
    }

    public LauncherUpdateStatus checkUpdates() {
        return send("updates/check", "GET", null, new TypeReference<>() {});
    }

    public DownloadStatus prepareVersion(String version) {
        return send("versions/prepare", "POST", Map.of("version", version), new TypeReference<>() {});
    }

    public String getModpackCompatibilityMode() {
        Map<String, Object> response = send("settings/modpack-compat", "GET", null, new TypeReference<>() {});
        Object mode = response.get("mode");
        return mode == null ? "BOTH" : mode.toString();
    }

    public String setModpackCompatibilityMode(String mode) {
        Map<String, Object> response = send("settings/modpack-compat", "POST", Map.of("mode", mode), new TypeReference<>() {});
        Object applied = response.get("mode");
        return applied == null ? "BOTH" : applied.toString();
    }

    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        return send("launch/" + launchId + "/output?from=" + fromIndex, "GET", null, new TypeReference<>() {});
    }

    public boolean isGameAlive(String launchId) {
        Map<String, Object> res = send("launch/" + launchId + "/alive", "GET", null, new TypeReference<>() {});
        return Boolean.TRUE.equals(res.get("alive"));
    }

    private <T> T send(String path, String method, Object body, TypeReference<T> typeReference) {
        try {
            HttpRequest request = buildRequest(path, method, body);
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() >= 400) {
                throw new IllegalStateException("Error API " + response.statusCode() + ": " + response.body());
            }
            return objectMapper.readValue(response.body(), typeReference);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo parsear la respuesta", ex);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("Llamada interrumpida", ex);
        }
    }

    private HttpRequest buildRequest(String path, String method, Object body) throws IOException {
        HttpRequest.Builder builder = HttpRequest.newBuilder()
                .uri(baseUri.resolve(path))
                .timeout(Duration.ofSeconds(10))
                .header("Content-Type", "application/json");

        if ("GET".equalsIgnoreCase(method)) {
            return builder.GET().build();
        }
        if ("DELETE".equalsIgnoreCase(method) && body == null) {
            return builder.DELETE().build();
        }

        byte[] payload = objectMapper.writeValueAsBytes(body);
        return builder.method(method, HttpRequest.BodyPublishers.ofByteArray(payload)).build();
    }
}

package am.froshy.launcher.api.internal;

import am.froshy.launcher.application.LauncherService;
import am.froshy.launcher.application.LauncherUpdateService;
import am.froshy.launcher.application.ModpackCompatibilityMode;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.MinecraftProfile;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.util.List;
import java.util.Map;
import java.util.concurrent.Executors;

public final class InternalApiServer {
    private final HttpServer server;
    private final LauncherService launcherService;
    private final LauncherUpdateService updateService;
    private final ObjectMapper objectMapper;

    public InternalApiServer(int port, LauncherService launcherService, LauncherUpdateService updateService) {
        try {
            this.server = HttpServer.create(new InetSocketAddress(port), 0);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo levantar la API interna", ex);
        }

        this.launcherService = launcherService;
        this.updateService = updateService;
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
        this.server.setExecutor(Executors.newCachedThreadPool());
        createContexts();
    }

    public void start() {
        server.start();
    }

    public void stop() {
        launcherService.shutdown();
        server.stop(0);
    }

    public int getPort() {
        return server.getAddress().getPort();
    }

    private void createContexts() {
        server.createContext("/internal/v1/health",           exchange -> withErrorHandling(exchange, this::handleHealth));
        server.createContext("/internal/v1/profiles",         exchange -> withErrorHandling(exchange, this::handleProfiles));
        server.createContext("/internal/v1/launch",           exchange -> withErrorHandling(exchange, this::handleLaunch));
        server.createContext("/internal/v1/launch-prepared",  exchange -> withErrorHandling(exchange, this::handleLaunchPrepared));
        server.createContext("/internal/v1/launch-prepared/start", exchange -> withErrorHandling(exchange, this::handleLaunchPreparedStart));
        server.createContext("/internal/v1/downloads",        exchange -> withErrorHandling(exchange, this::handleDownloads));
        server.createContext("/internal/v1/updates/check",    exchange -> withErrorHandling(exchange, this::handleUpdateCheck));
        server.createContext("/internal/v1/versions/prepare", exchange -> withErrorHandling(exchange, this::handlePrepareVersion));
        server.createContext("/internal/v1/settings/modpack-compat", exchange -> withErrorHandling(exchange, this::handleModpackCompatibility));
    }

    private void handleHealth(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, launcherService.health());
    }

    private void handleProfiles(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method) && "/internal/v1/profiles".equals(path)) {
            sendJson(exchange, 200, launcherService.listProfiles());
            return;
        }
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/profiles".equals(path)) {
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile created = launcherService.createProfile(profile);
            sendJson(exchange, 201, created);
            return;
        }

        if ("PUT".equalsIgnoreCase(method) && path.startsWith("/internal/v1/profiles/")) {
            String existingId = path.substring("/internal/v1/profiles/".length());
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile updated = launcherService.updateProfile(existingId, profile);
            sendJson(exchange, 200, updated);
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST", "PUT"));
    }

    private void handleLaunch(HttpExchange exchange) throws IOException {
        String path   = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();

        // POST /internal/v1/launch  → iniciar juego
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.launch(request));
            return;
        }

        // GET /internal/v1/launch/{id}/output?from=N  → líneas de output
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/output")) {
            String id = extractSegment(path, "/output");
            int fromIndex = parseQueryInt(exchange.getRequestURI().getQuery(), "from", 0);
            sendJson(exchange, 200, launcherService.getGameOutput(id, fromIndex));
            return;
        }

        // GET /internal/v1/launch/{id}/alive  → ¿el proceso sigue vivo?
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/alive")) {
            String id = extractSegment(path, "/alive");
            sendJson(exchange, 200, Map.of("alive", launcherService.isGameAlive(id)));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private static String extractSegment(String path, String suffix) {
        String base = "/internal/v1/launch/";
        String mid  = path.substring(base.length(), path.length() - suffix.length());
        return mid;
    }

    private static int parseQueryInt(String query, String key, int defaultVal) {
        if (query == null) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                try { return Integer.parseInt(param.substring(key.length() + 1)); }
                catch (NumberFormatException ignored) {}
            }
        }
        return defaultVal;
    }

    private void handleLaunchPrepared(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String path = exchange.getRequestURI().getPath();

        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch-prepared".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.prepareAndLaunch(request));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith("/internal/v1/launch-prepared/")) {
            String opId = path.substring("/internal/v1/launch-prepared/".length());
            launcherService.getPreparedLaunchStatus(opId)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Operacion no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleLaunchPreparedStart(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }
        LaunchRequest request = readBody(exchange, LaunchRequest.class);
        sendJson(exchange, 202, launcherService.startPreparedLaunch(request));
    }

    private void handleDownloads(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String fullPath = exchange.getRequestURI().getPath();
        String basePath = "/internal/v1/downloads";

        if ("POST".equalsIgnoreCase(method) && basePath.equals(fullPath)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            sendJson(exchange, 202, launcherService.startDownload(request.get("target")));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && fullPath.startsWith(basePath + "/")) {
            String id = fullPath.substring((basePath + "/").length());
            launcherService.getDownloadStatus(id)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Descarga no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleUpdateCheck(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, updateService.checkForUpdates());
    }

    private void handlePrepareVersion(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }

        Map<String, String> request = readBody(exchange, new TypeReference<>() {});
        String version = request.get("version");
        sendJson(exchange, 202, launcherService.prepareVersion(version));
    }

    private void handleModpackCompatibility(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method)) {
            ModpackCompatibilityMode mode = launcherService.getModpackCompatibilityMode();
            sendJson(exchange, 200, Map.of(
                    "mode", mode.name(),
                    "allowedSources", switch (mode) {
                        case BOTH -> List.of("MODRINTH", "CURSEFORGE");
                        case MODRINTH_ONLY -> List.of("MODRINTH");
                        case CURSEFORGE_ONLY -> List.of("CURSEFORGE");
                    }
            ));
            return;
        }

        if ("POST".equalsIgnoreCase(method)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            String rawMode = request.get("mode");
            ModpackCompatibilityMode mode = ModpackCompatibilityMode.fromEnvironment(rawMode);
            ModpackCompatibilityMode applied = launcherService.setModpackCompatibilityMode(mode);
            sendJson(exchange, 200, Map.of("mode", applied.name()));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST"));
    }

    private <T> T readBody(HttpExchange exchange, Class<T> type) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, type);
        }
    }

    private <T> T readBody(HttpExchange exchange, TypeReference<T> typeReference) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, typeReference);
        }
    }

    private void withErrorHandling(HttpExchange exchange, ExchangeHandler handler) throws IOException {
        try {
            handler.handle(exchange);
        } catch (IllegalArgumentException ex) {
            sendJson(exchange, 400, Map.of("error", ex.getMessage()));
        } catch (Exception ex) {
            sendJson(exchange, 500, Map.of("error", "Error interno", "detail", ex.getMessage()));
        } finally {
            exchange.close();
        }
    }

    private void sendMethodNotAllowed(HttpExchange exchange, List<String> allowedMethods) throws IOException {
        exchange.getResponseHeaders().set("Allow", String.join(", ", allowedMethods));
        sendJson(exchange, 405, Map.of("error", "Metodo no permitido"));
    }

    private void sendJson(HttpExchange exchange, int statusCode, Object body) throws IOException {
        byte[] payload = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsBytes(body);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(statusCode, payload.length);
        exchange.getResponseBody().write(payload);
    }

    private void sendJsonUnchecked(HttpExchange exchange, int statusCode, Object body) {
        try {
            sendJson(exchange, statusCode, body);
        } catch (IOException ex) {
            throw new IllegalStateException(ex);
        }
    }

    @FunctionalInterface
    private interface ExchangeHandler {
        void handle(HttpExchange exchange) throws IOException;
    }
}

package am.froshy.launcher.api.internal;

import am.froshy.launcher.application.LauncherService;
import am.froshy.launcher.application.LauncherUpdateService;
import am.froshy.launcher.application.ModpackCompatibilityMode;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.MinecraftProfile;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.sun.net.httpserver.HttpExchange;
import com.sun.net.httpserver.HttpServer;

import java.io.IOException;
import java.io.InputStream;
import java.net.InetSocketAddress;
import java.util.List;
import java.util.Map;
import java.util.concurrent.Executors;

public final class InternalApiServer {
    private final HttpServer server;
    private final LauncherService launcherService;
    private final LauncherUpdateService updateService;
    private final ObjectMapper objectMapper;

    public InternalApiServer(int port, LauncherService launcherService, LauncherUpdateService updateService) {
        try {
            this.server = HttpServer.create(new InetSocketAddress(port), 0);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo levantar la API interna", ex);
        }

        this.launcherService = launcherService;
        this.updateService = updateService;
        this.objectMapper = new ObjectMapper().findAndRegisterModules();
        this.server.setExecutor(Executors.newCachedThreadPool());
        createContexts();
    }

    public void start() {
        server.start();
    }

    public void stop() {
        launcherService.shutdown();
        server.stop(0);
    }

    public int getPort() {
        return server.getAddress().getPort();
    }

    private void createContexts() {
        server.createContext("/internal/v1/health",           exchange -> withErrorHandling(exchange, this::handleHealth));
        server.createContext("/internal/v1/profiles",         exchange -> withErrorHandling(exchange, this::handleProfiles));
        server.createContext("/internal/v1/launch",           exchange -> withErrorHandling(exchange, this::handleLaunch));
        server.createContext("/internal/v1/launch-prepared",  exchange -> withErrorHandling(exchange, this::handleLaunchPrepared));
        server.createContext("/internal/v1/launch-prepared/start", exchange -> withErrorHandling(exchange, this::handleLaunchPreparedStart));
        server.createContext("/internal/v1/downloads",        exchange -> withErrorHandling(exchange, this::handleDownloads));
        server.createContext("/internal/v1/updates/check",    exchange -> withErrorHandling(exchange, this::handleUpdateCheck));
        server.createContext("/internal/v1/versions/prepare", exchange -> withErrorHandling(exchange, this::handlePrepareVersion));
        server.createContext("/internal/v1/settings/modpack-compat", exchange -> withErrorHandling(exchange, this::handleModpackCompatibility));
    }

    private void handleHealth(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, launcherService.health());
    }

    private void handleProfiles(HttpExchange exchange) throws IOException {
        String path = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();
        String profilePrefix = "/internal/v1/profiles/";

        if ("GET".equalsIgnoreCase(method) && "/internal/v1/profiles".equals(path)) {
            sendJson(exchange, 200, launcherService.listProfiles());
            return;
        }
        if ("GET".equalsIgnoreCase(method)
                && path.startsWith(profilePrefix)
                && path.endsWith("/instance-path")) {
            String profileId = path.substring(profilePrefix.length(), path.length() - "/instance-path".length());
            sendJson(exchange, 200, Map.of(
                    "profileId", profileId,
                    "instancePath", launcherService.getProfileInstancePath(profileId)
            ));
            return;
        }
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/profiles".equals(path)) {
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile created = launcherService.createProfile(profile);
            sendJson(exchange, 201, created);
            return;
        }

        if ("PUT".equalsIgnoreCase(method) && path.startsWith(profilePrefix) && !path.endsWith("/instance-path")) {
            String existingId = path.substring(profilePrefix.length());
            MinecraftProfile profile = readBody(exchange, MinecraftProfile.class);
            MinecraftProfile updated = launcherService.updateProfile(existingId, profile);
            sendJson(exchange, 200, updated);
            return;
        }

        if ("DELETE".equalsIgnoreCase(method) && path.startsWith(profilePrefix) && !path.endsWith("/instance-path")) {
            String profileId = path.substring(profilePrefix.length());
            MinecraftProfile deleted = launcherService.deleteProfile(profileId);
            sendJson(exchange, 200, Map.of(
                    "deletedProfileId", deleted.id(),
                    "instanceDeleted", true
            ));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST", "PUT", "DELETE"));
    }

    private void handleLaunch(HttpExchange exchange) throws IOException {
        String path   = exchange.getRequestURI().getPath();
        String method = exchange.getRequestMethod();

        // POST /internal/v1/launch  → iniciar juego
        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.launch(request));
            return;
        }

        // GET /internal/v1/launch/{id}/output?from=N  → líneas de output
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/output")) {
            String id = extractSegment(path, "/output");
            int fromIndex = parseQueryInt(exchange.getRequestURI().getQuery(), "from", 0);
            sendJson(exchange, 200, launcherService.getGameOutput(id, fromIndex));
            return;
        }

        // GET /internal/v1/launch/{id}/alive  → ¿el proceso sigue vivo?
        if ("GET".equalsIgnoreCase(method) && path.endsWith("/alive")) {
            String id = extractSegment(path, "/alive");
            sendJson(exchange, 200, Map.of("alive", launcherService.isGameAlive(id)));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private static String extractSegment(String path, String suffix) {
        String base = "/internal/v1/launch/";
        String mid  = path.substring(base.length(), path.length() - suffix.length());
        return mid;
    }

    private static int parseQueryInt(String query, String key, int defaultVal) {
        if (query == null) return defaultVal;
        for (String param : query.split("&")) {
            if (param.startsWith(key + "=")) {
                try { return Integer.parseInt(param.substring(key.length() + 1)); }
                catch (NumberFormatException ignored) {}
            }
        }
        return defaultVal;
    }

    private void handleLaunchPrepared(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String path = exchange.getRequestURI().getPath();

        if ("POST".equalsIgnoreCase(method) && "/internal/v1/launch-prepared".equals(path)) {
            LaunchRequest request = readBody(exchange, LaunchRequest.class);
            sendJson(exchange, 202, launcherService.prepareAndLaunch(request));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && path.startsWith("/internal/v1/launch-prepared/")) {
            String opId = path.substring("/internal/v1/launch-prepared/".length());
            launcherService.getPreparedLaunchStatus(opId)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Operacion no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleLaunchPreparedStart(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }
        LaunchRequest request = readBody(exchange, LaunchRequest.class);
        sendJson(exchange, 202, launcherService.startPreparedLaunch(request));
    }

    private void handleDownloads(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        String fullPath = exchange.getRequestURI().getPath();
        String basePath = "/internal/v1/downloads";

        if ("POST".equalsIgnoreCase(method) && basePath.equals(fullPath)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            sendJson(exchange, 202, launcherService.startDownload(request.get("target")));
            return;
        }

        if ("GET".equalsIgnoreCase(method) && fullPath.startsWith(basePath + "/")) {
            String id = fullPath.substring((basePath + "/").length());
            launcherService.getDownloadStatus(id)
                    .ifPresentOrElse(
                            status -> sendJsonUnchecked(exchange, 200, status),
                            () -> sendJsonUnchecked(exchange, 404, Map.of("error", "Descarga no encontrada"))
                    );
            return;
        }

        sendMethodNotAllowed(exchange, List.of("POST", "GET"));
    }

    private void handleUpdateCheck(HttpExchange exchange) throws IOException {
        if (!"GET".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("GET"));
            return;
        }
        sendJson(exchange, 200, updateService.checkForUpdates());
    }

    private void handlePrepareVersion(HttpExchange exchange) throws IOException {
        if (!"POST".equalsIgnoreCase(exchange.getRequestMethod())) {
            sendMethodNotAllowed(exchange, List.of("POST"));
            return;
        }

        Map<String, String> request = readBody(exchange, new TypeReference<>() {});
        String version = request.get("version");
        sendJson(exchange, 202, launcherService.prepareVersion(version));
    }

    private void handleModpackCompatibility(HttpExchange exchange) throws IOException {
        String method = exchange.getRequestMethod();
        if ("GET".equalsIgnoreCase(method)) {
            ModpackCompatibilityMode mode = launcherService.getModpackCompatibilityMode();
            sendJson(exchange, 200, Map.of(
                    "mode", mode.name(),
                    "allowedSources", switch (mode) {
                        case BOTH -> List.of("MODRINTH", "CURSEFORGE");
                        case MODRINTH_ONLY -> List.of("MODRINTH");
                        case CURSEFORGE_ONLY -> List.of("CURSEFORGE");
                    }
            ));
            return;
        }

        if ("POST".equalsIgnoreCase(method)) {
            Map<String, String> request = readBody(exchange, new TypeReference<>() {});
            String rawMode = request.get("mode");
            ModpackCompatibilityMode mode = ModpackCompatibilityMode.fromEnvironment(rawMode);
            ModpackCompatibilityMode applied = launcherService.setModpackCompatibilityMode(mode);
            sendJson(exchange, 200, Map.of("mode", applied.name()));
            return;
        }

        sendMethodNotAllowed(exchange, List.of("GET", "POST"));
    }

    private <T> T readBody(HttpExchange exchange, Class<T> type) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, type);
        }
    }

    private <T> T readBody(HttpExchange exchange, TypeReference<T> typeReference) throws IOException {
        try (InputStream body = exchange.getRequestBody()) {
            return objectMapper.readValue(body, typeReference);
        }
    }

    private void withErrorHandling(HttpExchange exchange, ExchangeHandler handler) throws IOException {
        try {
            handler.handle(exchange);
        } catch (IllegalArgumentException ex) {
            sendJson(exchange, 400, Map.of("error", ex.getMessage()));
        } catch (Exception ex) {
            sendJson(exchange, 500, Map.of("error", "Error interno", "detail", ex.getMessage()));
        } finally {
            exchange.close();
        }
    }

    private void sendMethodNotAllowed(HttpExchange exchange, List<String> allowedMethods) throws IOException {
        exchange.getResponseHeaders().set("Allow", String.join(", ", allowedMethods));
        sendJson(exchange, 405, Map.of("error", "Metodo no permitido"));
    }

    private void sendJson(HttpExchange exchange, int statusCode, Object body) throws IOException {
        byte[] payload = objectMapper.writerWithDefaultPrettyPrinter().writeValueAsBytes(body);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(statusCode, payload.length);
        exchange.getResponseBody().write(payload);
    }

    private void sendJsonUnchecked(HttpExchange exchange, int statusCode, Object body) {
        try {
            sendJson(exchange, statusCode, body);
        } catch (IOException ex) {
            throw new IllegalStateException(ex);
        }
    }

    @FunctionalInterface
    private interface ExchangeHandler {
        void handle(HttpExchange exchange) throws IOException;
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherConfig;
import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.ModpackManifest;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import am.froshy.launcher.infrastructure.ProfileStore;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.function.BiConsumer;

public final class LauncherService {

    private static final int MAX_OUTPUT_LINES = 2000;

    private final LauncherConfig config;
    private final ProfileStore profileStore;
    private final MinecraftVersionDownloader versionDownloader;
    private final ModpackInstaller modpackInstaller;
    private volatile ModpackCompatibilityMode modpackCompatibilityMode;

    private final Map<String, MinecraftProfile> profiles         = new ConcurrentHashMap<>();
    private final Map<String, DownloadStatus>   downloads        = new ConcurrentHashMap<>();
    private final Map<String, String>           activeVersionDls = new ConcurrentHashMap<>();
    private final Map<String, ScheduledFuture<?>> downloadTasks  = new ConcurrentHashMap<>();
    private final Map<String, PreparedLaunchStatus> preparedLaunches = new ConcurrentHashMap<>();

    // Procesos de juego activos
    private final Map<String, Process>       activeProcesses = new ConcurrentHashMap<>();
    private final Map<String, List<String>>  processOutputs  = new ConcurrentHashMap<>();

    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

    public LauncherService(LauncherConfig config, ProfileStore profileStore) {
        this(config, profileStore, new MojangVersionDownloader(), new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader) {
        this(config, profileStore, versionDownloader, new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller) {
        this(config, profileStore, versionDownloader, modpackInstaller,
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller,
                           ModpackCompatibilityMode modpackCompatibilityMode) {
        this.config            = config;
        this.profileStore      = profileStore;
        this.versionDownloader = versionDownloader;
        this.modpackInstaller  = modpackInstaller;
        this.modpackCompatibilityMode = modpackCompatibilityMode == null
                ? ModpackCompatibilityMode.BOTH
                : modpackCompatibilityMode;
        profileStore.load().forEach(p -> profiles.put(p.id(), p));
    }

    // ── Perfiles ─────────────────────────────────────────────────────────

    public List<MinecraftProfile> listProfiles() {
        return new ArrayList<>(profiles.values());
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        if (profiles.containsKey(profile.id()))
            throw new IllegalArgumentException("Ya existe un perfil con id: " + profile.id());
        ensureProfileInstanceDirectory(profile);
        profiles.put(profile.id(), profile);
        profileStore.save(profiles.values());
        return profile;
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile changes) {
        if (existingId == null || existingId.isBlank()) {
            throw new IllegalArgumentException("existingId es obligatorio");
        }
        if (!profiles.containsKey(existingId)) {
            throw new IllegalArgumentException("Perfil no encontrado: " + existingId);
        }

        // En modo edicion, la ID del formulario se ignora y se conserva la original.
        MinecraftProfile updated = new MinecraftProfile(
                existingId,
                changes.displayName(),
                changes.javaPath(),
                changes.gameVersion(),
                changes.jvmArgs(),
                changes.gameArgs(),
                changes.loaderType(),
                changes.loaderVersion(),
                changes.modpackPath()
        );

        ensureProfileInstanceDirectory(updated);
        profiles.put(existingId, updated);
        profileStore.save(profiles.values());
        return updated;
    }

    // ── Lanzamiento ───────────────────────────────────────────────────────

    public LaunchResult launch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        String effectiveVersion;
        try {
            effectiveVersion = resolveLaunchPlan(profile).effectiveVersionId();
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo leer el modpack del perfil: " + ex.getMessage(), ex);
        }

        return launchWithVersion(request, profile, effectiveVersion, instanceDir);
    }

    private LaunchResult launchWithVersion(LaunchRequest request, MinecraftProfile profile,
                                           String effectiveVersion, Path gameDir) {

        // Extraer username de los gameArgs del perfil (--username <valor>)
        String username = extractUsername(profile);

        // Construir instalación (classpath, mainClass, args resueltos)
        VersionInstallation install;
        try {
            install = versionDownloader.buildInstallation(
                    effectiveVersion, gameDir, username);
        } catch (IOException ex) {
            throw new IllegalStateException(
                    "Version " + effectiveVersion + " no preparada: " + ex.getMessage(), ex);
        }

        // Construir comando completo
        List<String> cmd = new ArrayList<>();
        cmd.add(profile.javaPath().isBlank() ? "java" : profile.javaPath());
        // JVM args del perfil (memoria, etc.) van ANTES de los del sistema
        cmd.addAll(profile.jvmArgs());
        // JVM args de la instalación (classpath, library.path, etc.)
        cmd.addAll(install.jvmArguments());
        // Main class
        cmd.add(install.mainClass());
        // Game arguments
        cmd.addAll(install.gameArguments());
        // Demo mode
        if (request.demoMode()) cmd.add("--demo");

        String launchId  = UUID.randomUUID().toString();
        String cmdLine   = String.join(" ", cmd);

        try {
            Files.createDirectories(gameDir);
            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.directory(gameDir.toFile());
            pb.redirectErrorStream(true);   // stderr → stdout

            Process process = pb.start();
            activeProcesses.put(launchId, process);

            // Hilo lector de output
            startOutputReader(launchId, process);

            return new LaunchResult(launchId, profile.id(), cmdLine, Instant.now(), "STARTED");

        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo iniciar Minecraft: " + ex.getMessage(), ex);
        }
    }

    /** Prepara la version del perfil y la lanza en un solo flujo. */
    public LaunchResult prepareAndLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        try {
            LaunchPlan plan = prepareProfile(profile, instanceDir, (p, m) -> {});
            return launchWithVersion(request, profile, plan.effectiveVersionId(), instanceDir);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        }
    }

    public PreparedLaunchStatus startPreparedLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));

        String operationId = "pl-" + UUID.randomUUID();
        PreparedLaunchStatus queued = new PreparedLaunchStatus(
                operationId,
                profile.id(),
                profile.gameVersion(),
                "QUEUED",
                0,
                "En cola..."
        );
        preparedLaunches.put(operationId, queued);

        scheduler.execute(() -> runPreparedLaunch(operationId, request, profile));
        return queued;
    }

    public Optional<PreparedLaunchStatus> getPreparedLaunchStatus(String operationId) {
        return Optional.ofNullable(preparedLaunches.get(operationId));
    }

    // ── Output del proceso ────────────────────────────────────────────────

    /** Devuelve líneas nuevas desde {@code fromIndex} y el estado del proceso. */
    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        List<String> buffer = processOutputs.get(launchId);
        boolean alive = isGameAlive(launchId);

        if (buffer == null) {
            return Map.of("lines", List.of(), "total", 0, "alive", alive);
        }
        synchronized (buffer) {
            int total = buffer.size();
            List<String> newLines = (fromIndex < total)
                    ? List.copyOf(buffer.subList(fromIndex, total))
                    : List.of();
            return Map.of("lines", newLines, "total", total, "alive", alive);
        }
    }

    public boolean isGameAlive(String launchId) {
        Process p = activeProcesses.get(launchId);
        return p != null && p.isAlive();
    }

    private void startOutputReader(String launchId, Process process) {
        LinkedList<String> buffer = new LinkedList<>();
        processOutputs.put(launchId, buffer);

        Thread t = new Thread(() -> {
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = br.readLine()) != null) {
                    synchronized (buffer) {
                        buffer.add(line);
                        if (buffer.size() > MAX_OUTPUT_LINES)
                            buffer.removeFirst();
                    }
                }
            } catch (IOException ignored) {}
            // Proceso terminado
            activeProcesses.remove(launchId);
        }, "game-reader-" + launchId.substring(0, 8));
        t.setDaemon(true);
        t.start();
    }

    // ── Descarga / preparación de versión ────────────────────────────────

    public DownloadStatus prepareVersion(String gameVersion) {
        if (gameVersion == null || gameVersion.isBlank())
            throw new IllegalArgumentException("version es obligatoria");

        String target = "minecraft-" + gameVersion;

        // ¿Ya instalada completamente?
        if (isVersionInstalled(gameVersion)) {
            String id = "ready-" + UUID.randomUUID();
            DownloadStatus done = new DownloadStatus(id, target, "DONE", 100);
            downloads.put(id, done);
            return done;
        }

        // ¿Ya hay una descarga activa?
        String existingId = activeVersionDls.get(gameVersion);
        if (existingId != null) {
            DownloadStatus existing = downloads.get(existingId);
            if (existing != null && !isTerminal(existing.state())) return existing;
        }

        String downloadId = "dl-" + UUID.randomUUID();
        downloads.put(downloadId, new DownloadStatus(downloadId, target, "QUEUED", 0));
        activeVersionDls.put(gameVersion, downloadId);

        scheduler.execute(() -> {
            try {
                versionDownloader.downloadVersion(gameVersion, config.gameDirectory(), (prog, msg) -> {
                    int norm = Math.max(0, Math.min(prog, 100));
                    String state = norm >= 100 ? "DONE" : "IN_PROGRESS";
                    String message = msg != null ? msg : "";
                    downloads.put(downloadId, new DownloadStatus(downloadId, target, state, norm, message));
                });
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "DONE", 100, "Instalacion completada."));
            } catch (Exception ex) {
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "FAILED", 0,
                        "Error: " + ex.getMessage()));
            } finally {
                activeVersionDls.remove(gameVersion, downloadId);
            }
        });

        return downloads.get(downloadId);
    }

    public Optional<DownloadStatus> getDownloadStatus(String id) {
        return Optional.ofNullable(downloads.get(id));
    }

    public DownloadStatus startDownload(String target) {
        if (target == null || target.isBlank())
            throw new IllegalArgumentException("target es obligatorio");
        String id = UUID.randomUUID().toString();
        downloads.put(id, new DownloadStatus(id, target, "QUEUED", 0));
        ScheduledFuture<?> task = scheduler.scheduleAtFixedRate(() -> {
            DownloadStatus cur = downloads.get(id);
            if (cur == null || "DONE".equals(cur.state())) return;
            int next = Math.min(100, cur.progress() + 20);
            downloads.put(id, new DownloadStatus(id, target,
                    next >= 100 ? "DONE" : "IN_PROGRESS", next));
            if (next >= 100) {
                ScheduledFuture<?> t = downloadTasks.remove(id);
                if (t != null) t.cancel(false);
            }
        }, 200, 300, TimeUnit.MILLISECONDS);
        downloadTasks.put(id, task);
        return downloads.get(id);
    }

    // ── Salud y shutdown ─────────────────────────────────────────────────

    public Map<String, Object> health() {
        return Map.of(
                "status", "UP",
                "apiPort", config.internalApiPort(),
                "profiles", profiles.size(),
                "modpackCompatibility", modpackCompatibilityMode.name(),
                "timestamp", Instant.now().toString()
        );
    }

    public ModpackCompatibilityMode getModpackCompatibilityMode() {
        return modpackCompatibilityMode;
    }

    public ModpackCompatibilityMode setModpackCompatibilityMode(ModpackCompatibilityMode mode) {
        if (mode == null) {
            throw new IllegalArgumentException("mode es obligatorio");
        }
        this.modpackCompatibilityMode = mode;
        return this.modpackCompatibilityMode;
    }

    public String getProfileInstancePath(String profileId) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(profileId))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + profileId));
        return ensureProfileInstanceDirectory(profile).toAbsolutePath().toString();
    }

    public void shutdown() {
        downloadTasks.values().forEach(t -> t.cancel(false));
        scheduler.shutdownNow();
        activeProcesses.values().forEach(Process::destroy);
    }

    // ── Utilidades ────────────────────────────────────────────────────────

    private boolean isVersionInstalled(String version) {
        Path dir  = config.gameDirectory().resolve("versions").resolve(version);
        Path jar  = dir.resolve(version + ".jar");
        Path json = dir.resolve(version + ".json");
        try {
            return Files.exists(json) && Files.exists(jar) && Files.size(jar) > 10_000;
        } catch (IOException e) { return false; }
    }

    private boolean isTerminal(String state) {
        return "DONE".equals(state) || "FAILED".equals(state);
    }

    private String extractUsername(MinecraftProfile profile) {
        List<String> args = profile.gameArgs();
        for (int i = 0; i < args.size() - 1; i++) {
            if ("--username".equals(args.get(i))) return args.get(i + 1);
        }
        // Fallback: usar el nombre del perfil sin espacios
        return profile.displayName().replaceAll("\\s+", "_");
    }

    private void runPreparedLaunch(String operationId, LaunchRequest request, MinecraftProfile profile) {
        try {
            LaunchPlan basePlan = resolveLaunchPlan(profile);
            Path instanceDir = profileGameDirectory(profile);
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    1,
                    "Verificando instalacion de Minecraft " + basePlan.minecraftVersion() + "..."
            ));

            versionDownloader.downloadVersion(basePlan.minecraftVersion(), instanceDir, (progress, message) -> {
                int mappedProgress = Math.max(1, Math.min(60, progress * 60 / 100));
                String safeMessage = (message == null || message.isBlank())
                        ? "Preparando archivos de Minecraft..."
                        : message;
                preparedLaunches.put(operationId, new PreparedLaunchStatus(
                        operationId,
                        profile.id(),
                        basePlan.minecraftVersion(),
                        "PREPARING",
                        mappedProgress,
                        safeMessage
                ));
            });

            LaunchPlan readyPlan = prepareLoadersAndModpack(operationId, profile, basePlan, instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "STARTING",
                    95,
                    "Iniciando Minecraft..."
            ));

            LaunchResult result = launchWithVersion(request, profile, readyPlan.effectiveVersionId(), instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "DONE",
                    100,
                    "Minecraft iniciado.",
                    result.launchId()
            ));
        } catch (Exception ex) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    profile.gameVersion(),
                    "FAILED",
                    0,
                    "Error: " + ex.getMessage()
            ));
        }
    }

    private LaunchPlan prepareLoadersAndModpack(String operationId, MinecraftProfile profile,
                                                LaunchPlan basePlan, Path gameDir)
            throws IOException, InterruptedException {
        String effectiveVersion = basePlan.minecraftVersion();

        if (basePlan.hasLoader()) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    62,
                    "Instalando loader " + basePlan.loaderType() + " " + basePlan.loaderVersion() + "..."
            ));

            effectiveVersion = modpackInstaller.installLoader(
                    basePlan.loaderType(),
                    basePlan.minecraftVersion(),
                    basePlan.loaderVersion(),
                    gameDir,
                    (progress, message) -> preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            basePlan.minecraftVersion(),
                            "PREPARING",
                            60 + Math.max(0, Math.min(progress, 100)) * 25 / 100,
                            message == null || message.isBlank() ? "Instalando loader..." : message
                    ))
            );
        }

        if (basePlan.hasModpack()) {
            Path modpackPath = basePlan.modpackPath();
            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            String launchVersion = effectiveVersion;
            modpackInstaller.installModpackFiles(modpackPath, manifest, gameDir, (progress, message) ->
                    preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            launchVersion,
                            "PREPARING",
                            85 + Math.max(0, Math.min(progress, 100)) * 10 / 100,
                            message == null || message.isBlank() ? "Instalando modpack..." : message
                    ))
            );
        }

        return new LaunchPlan(
                basePlan.minecraftVersion(),
                basePlan.loaderType(),
                basePlan.loaderVersion(),
                basePlan.modpackPath(),
                effectiveVersion
        );
    }

    private LaunchPlan prepareProfile(MinecraftProfile profile, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        LaunchPlan plan = resolveLaunchPlan(profile);

        progress.accept(0, "Preparando Minecraft " + plan.minecraftVersion() + "...");
        versionDownloader.downloadVersion(plan.minecraftVersion(), gameDir, progress);

        String effectiveVersion = plan.minecraftVersion();
        if (plan.hasLoader()) {
            effectiveVersion = modpackInstaller.installLoader(
                    plan.loaderType(),
                    plan.minecraftVersion(),
                    plan.loaderVersion(),
                    gameDir,
                    progress
            );
        }

        if (plan.hasModpack()) {
            ModpackManifest manifest = parseAndValidateModpack(plan.modpackPath());
            modpackInstaller.installModpackFiles(plan.modpackPath(), manifest, gameDir, progress);
        }

        return new LaunchPlan(plan.minecraftVersion(), plan.loaderType(), plan.loaderVersion(), plan.modpackPath(), effectiveVersion);
    }

    private LaunchPlan resolveLaunchPlan(MinecraftProfile profile) throws IOException {
        String minecraftVersion = profile.gameVersion();
        String loaderType = profile.loaderType();
        String loaderVersion = profile.loaderVersion();
        Path modpackPath = null;

        if (profile.hasModpack()) {
            modpackPath = Path.of(profile.modpackPath());
            if (!Files.exists(modpackPath)) {
                throw new IOException("No existe el modpack en ruta: " + modpackPath);
            }

            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            if (manifest.minecraftVersion() != null && !manifest.minecraftVersion().isBlank()) {
                minecraftVersion = manifest.minecraftVersion();
            }
            if (manifest.loaderType() != null && !manifest.loaderType().isBlank()) {
                loaderType = manifest.loaderType();
            }
            if (manifest.loaderVersion() != null && !manifest.loaderVersion().isBlank()) {
                loaderVersion = manifest.loaderVersion();
            }
        }

        String effectiveVersion = ModpackInstaller.computeEffectiveVersionId(
                minecraftVersion,
                loaderType,
                loaderVersion
        );

        return new LaunchPlan(minecraftVersion, loaderType, loaderVersion, modpackPath, effectiveVersion);
    }

    private ModpackManifest parseAndValidateModpack(Path modpackPath) throws IOException {
        ModpackManifest manifest = modpackInstaller.parseModpack(modpackPath);
        if (!modpackCompatibilityMode.isAllowed(manifest.source())) {
            throw new IOException("Formato de modpack no permitido por compatibilidad actual ("
                    + modpackCompatibilityMode + "): " + manifest.source());
        }
        return manifest;
    }

    private Path profileGameDirectory(MinecraftProfile profile) {
        String safeId = profile.id().replaceAll("[^a-zA-Z0-9._-]", "_");
        return config.gameDirectory().resolve("instances").resolve(safeId);
    }

    private Path ensureProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        try {
            Files.createDirectories(instanceDir);
            return instanceDir;
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar la instancia del perfil " + profile.id(), ex);
        }
    }

    private record LaunchPlan(
            String minecraftVersion,
            String loaderType,
            String loaderVersion,
            Path modpackPath,
            String effectiveVersionId
    ) {
        private boolean hasLoader() {
            return loaderType != null && !loaderType.isBlank() && !"VANILLA".equalsIgnoreCase(loaderType);
        }

        private boolean hasModpack() {
            return modpackPath != null;
        }
    }
}

package am.froshy.launcher.application;

import am.froshy.launcher.config.LauncherConfig;
import am.froshy.launcher.domain.DownloadStatus;
import am.froshy.launcher.domain.LaunchRequest;
import am.froshy.launcher.domain.LaunchResult;
import am.froshy.launcher.domain.MinecraftProfile;
import am.froshy.launcher.domain.ModpackManifest;
import am.froshy.launcher.domain.PreparedLaunchStatus;
import am.froshy.launcher.infrastructure.ProfileStore;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.ScheduledFuture;
import java.util.concurrent.TimeUnit;
import java.util.function.BiConsumer;

public final class LauncherService {

    private static final int MAX_OUTPUT_LINES = 2000;

    private final LauncherConfig config;
    private final ProfileStore profileStore;
    private final MinecraftVersionDownloader versionDownloader;
    private final ModpackInstaller modpackInstaller;
    private volatile ModpackCompatibilityMode modpackCompatibilityMode;

    private final Map<String, MinecraftProfile> profiles         = new ConcurrentHashMap<>();
    private final Map<String, DownloadStatus>   downloads        = new ConcurrentHashMap<>();
    private final Map<String, String>           activeVersionDls = new ConcurrentHashMap<>();
    private final Map<String, ScheduledFuture<?>> downloadTasks  = new ConcurrentHashMap<>();
    private final Map<String, PreparedLaunchStatus> preparedLaunches = new ConcurrentHashMap<>();

    // Procesos de juego activos
    private final Map<String, Process>       activeProcesses = new ConcurrentHashMap<>();
    private final Map<String, String>        activeProcessProfiles = new ConcurrentHashMap<>();
    private final Map<String, List<String>>  processOutputs  = new ConcurrentHashMap<>();

    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(2);

    public LauncherService(LauncherConfig config, ProfileStore profileStore) {
        this(config, profileStore, new MojangVersionDownloader(), new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader) {
        this(config, profileStore, versionDownloader, new ModpackInstaller(),
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller) {
        this(config, profileStore, versionDownloader, modpackInstaller,
                ModpackCompatibilityMode.fromEnvironment(System.getenv("FROSHY_MODPACK_COMPAT")));
    }

    public LauncherService(LauncherConfig config, ProfileStore profileStore,
                           MinecraftVersionDownloader versionDownloader,
                           ModpackInstaller modpackInstaller,
                           ModpackCompatibilityMode modpackCompatibilityMode) {
        this.config            = config;
        this.profileStore      = profileStore;
        this.versionDownloader = versionDownloader;
        this.modpackInstaller  = modpackInstaller;
        this.modpackCompatibilityMode = modpackCompatibilityMode == null
                ? ModpackCompatibilityMode.BOTH
                : modpackCompatibilityMode;
        profileStore.load().forEach(p -> profiles.put(p.id(), p));
    }

    // ── Perfiles ─────────────────────────────────────────────────────────

    public List<MinecraftProfile> listProfiles() {
        return new ArrayList<>(profiles.values());
    }

    public MinecraftProfile createProfile(MinecraftProfile profile) {
        if (profiles.containsKey(profile.id()))
            throw new IllegalArgumentException("Ya existe un perfil con id: " + profile.id());
        ensureProfileInstanceDirectory(profile);
        profiles.put(profile.id(), profile);
        profileStore.save(profiles.values());
        return profile;
    }

    public MinecraftProfile updateProfile(String existingId, MinecraftProfile changes) {
        if (existingId == null || existingId.isBlank()) {
            throw new IllegalArgumentException("existingId es obligatorio");
        }
        if (!profiles.containsKey(existingId)) {
            throw new IllegalArgumentException("Perfil no encontrado: " + existingId);
        }

        // En modo edicion, la ID del formulario se ignora y se conserva la original.
        MinecraftProfile updated = new MinecraftProfile(
                existingId,
                changes.displayName(),
                changes.javaPath(),
                changes.gameVersion(),
                changes.jvmArgs(),
                changes.gameArgs(),
                changes.loaderType(),
                changes.loaderVersion(),
                changes.modpackPath()
        );

        ensureProfileInstanceDirectory(updated);
        profiles.put(existingId, updated);
        profileStore.save(profiles.values());
        return updated;
    }

    public MinecraftProfile deleteProfile(String profileId) {
        if (profileId == null || profileId.isBlank()) {
            throw new IllegalArgumentException("profileId es obligatorio");
        }

        MinecraftProfile removed = profiles.remove(profileId);
        if (removed == null) {
            throw new IllegalArgumentException("Perfil no encontrado: " + profileId);
        }

        stopActiveProcessesForProfile(profileId);
        profileStore.save(profiles.values());
        deleteProfileInstanceDirectory(removed);
        return removed;
    }

    // ── Lanzamiento ───────────────────────────────────────────────────────

    public LaunchResult launch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        String effectiveVersion;
        try {
            effectiveVersion = resolveLaunchPlan(profile).effectiveVersionId();
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo leer el modpack del perfil: " + ex.getMessage(), ex);
        }

        return launchWithVersion(request, profile, effectiveVersion, instanceDir);
    }

    private LaunchResult launchWithVersion(LaunchRequest request, MinecraftProfile profile,
                                           String effectiveVersion, Path gameDir) {

        // Extraer username de los gameArgs del perfil (--username <valor>)
        String username = extractUsername(profile);

        // Construir instalación (classpath, mainClass, args resueltos)
        VersionInstallation install;
        try {
            install = versionDownloader.buildInstallation(
                    effectiveVersion, gameDir, username);
        } catch (IOException ex) {
            throw new IllegalStateException(
                    "Version " + effectiveVersion + " no preparada: " + ex.getMessage(), ex);
        }

        // Construir comando completo
        List<String> cmd = new ArrayList<>();
        cmd.add(profile.javaPath().isBlank() ? "java" : profile.javaPath());
        // JVM args del perfil (memoria, etc.) van ANTES de los del sistema
        cmd.addAll(profile.jvmArgs());
        // JVM args de la instalación (classpath, library.path, etc.)
        cmd.addAll(install.jvmArguments());
        // Main class
        cmd.add(install.mainClass());
        // Game arguments
        cmd.addAll(install.gameArguments());
        // Demo mode
        if (request.demoMode()) cmd.add("--demo");

        String launchId  = UUID.randomUUID().toString();
        String cmdLine   = String.join(" ", cmd);

        try {
            Files.createDirectories(gameDir);
            ProcessBuilder pb = new ProcessBuilder(cmd);
            pb.directory(gameDir.toFile());
            pb.redirectErrorStream(true);   // stderr → stdout

            Process process = pb.start();
            activeProcesses.put(launchId, process);
            activeProcessProfiles.put(launchId, profile.id());

            // Hilo lector de output
            startOutputReader(launchId, process);

            return new LaunchResult(launchId, profile.id(), cmdLine, Instant.now(), "STARTED");

        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo iniciar Minecraft: " + ex.getMessage(), ex);
        }
    }

    /** Prepara la version del perfil y la lanza en un solo flujo. */
    public LaunchResult prepareAndLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));
        Path instanceDir = profileGameDirectory(profile);

        try {
            LaunchPlan plan = prepareProfile(profile, instanceDir, (p, m) -> {});
            return launchWithVersion(request, profile, plan.effectiveVersionId(), instanceDir);
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar el lanzamiento: " + ex.getMessage(), ex);
        }
    }

    public PreparedLaunchStatus startPreparedLaunch(LaunchRequest request) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(request.profileId()))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + request.profileId()));

        String operationId = "pl-" + UUID.randomUUID();
        PreparedLaunchStatus queued = new PreparedLaunchStatus(
                operationId,
                profile.id(),
                profile.gameVersion(),
                "QUEUED",
                0,
                "En cola..."
        );
        preparedLaunches.put(operationId, queued);

        scheduler.execute(() -> runPreparedLaunch(operationId, request, profile));
        return queued;
    }

    public Optional<PreparedLaunchStatus> getPreparedLaunchStatus(String operationId) {
        return Optional.ofNullable(preparedLaunches.get(operationId));
    }

    // ── Output del proceso ────────────────────────────────────────────────

    /** Devuelve líneas nuevas desde {@code fromIndex} y el estado del proceso. */
    public Map<String, Object> getGameOutput(String launchId, int fromIndex) {
        List<String> buffer = processOutputs.get(launchId);
        boolean alive = isGameAlive(launchId);

        if (buffer == null) {
            return Map.of("lines", List.of(), "total", 0, "alive", alive);
        }
        synchronized (buffer) {
            int total = buffer.size();
            List<String> newLines = (fromIndex < total)
                    ? List.copyOf(buffer.subList(fromIndex, total))
                    : List.of();
            return Map.of("lines", newLines, "total", total, "alive", alive);
        }
    }

    public boolean isGameAlive(String launchId) {
        Process p = activeProcesses.get(launchId);
        return p != null && p.isAlive();
    }

    private void startOutputReader(String launchId, Process process) {
        LinkedList<String> buffer = new LinkedList<>();
        processOutputs.put(launchId, buffer);

        Thread t = new Thread(() -> {
            try (BufferedReader br = new BufferedReader(
                    new InputStreamReader(process.getInputStream(), StandardCharsets.UTF_8))) {
                String line;
                while ((line = br.readLine()) != null) {
                    synchronized (buffer) {
                        buffer.add(line);
                        if (buffer.size() > MAX_OUTPUT_LINES)
                            buffer.removeFirst();
                    }
                }
            } catch (IOException ignored) {}
            // Proceso terminado
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }, "game-reader-" + launchId.substring(0, 8));
        t.setDaemon(true);
        t.start();
    }

    // ── Descarga / preparación de versión ────────────────────────────────

    public DownloadStatus prepareVersion(String gameVersion) {
        if (gameVersion == null || gameVersion.isBlank())
            throw new IllegalArgumentException("version es obligatoria");

        String target = "minecraft-" + gameVersion;

        // ¿Ya instalada completamente?
        if (isVersionInstalled(gameVersion)) {
            String id = "ready-" + UUID.randomUUID();
            DownloadStatus done = new DownloadStatus(id, target, "DONE", 100);
            downloads.put(id, done);
            return done;
        }

        // ¿Ya hay una descarga activa?
        String existingId = activeVersionDls.get(gameVersion);
        if (existingId != null) {
            DownloadStatus existing = downloads.get(existingId);
            if (existing != null && !isTerminal(existing.state())) return existing;
        }

        String downloadId = "dl-" + UUID.randomUUID();
        downloads.put(downloadId, new DownloadStatus(downloadId, target, "QUEUED", 0));
        activeVersionDls.put(gameVersion, downloadId);

        scheduler.execute(() -> {
            try {
                versionDownloader.downloadVersion(gameVersion, config.gameDirectory(), (prog, msg) -> {
                    int norm = Math.max(0, Math.min(prog, 100));
                    String state = norm >= 100 ? "DONE" : "IN_PROGRESS";
                    String message = msg != null ? msg : "";
                    downloads.put(downloadId, new DownloadStatus(downloadId, target, state, norm, message));
                });
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "DONE", 100, "Instalacion completada."));
            } catch (Exception ex) {
                downloads.put(downloadId, new DownloadStatus(downloadId, target, "FAILED", 0,
                        "Error: " + ex.getMessage()));
            } finally {
                activeVersionDls.remove(gameVersion, downloadId);
            }
        });

        return downloads.get(downloadId);
    }

    public Optional<DownloadStatus> getDownloadStatus(String id) {
        return Optional.ofNullable(downloads.get(id));
    }

    public DownloadStatus startDownload(String target) {
        if (target == null || target.isBlank())
            throw new IllegalArgumentException("target es obligatorio");
        String id = UUID.randomUUID().toString();
        downloads.put(id, new DownloadStatus(id, target, "QUEUED", 0));
        ScheduledFuture<?> task = scheduler.scheduleAtFixedRate(() -> {
            DownloadStatus cur = downloads.get(id);
            if (cur == null || "DONE".equals(cur.state())) return;
            int next = Math.min(100, cur.progress() + 20);
            downloads.put(id, new DownloadStatus(id, target,
                    next >= 100 ? "DONE" : "IN_PROGRESS", next));
            if (next >= 100) {
                ScheduledFuture<?> t = downloadTasks.remove(id);
                if (t != null) t.cancel(false);
            }
        }, 200, 300, TimeUnit.MILLISECONDS);
        downloadTasks.put(id, task);
        return downloads.get(id);
    }

    // ── Salud y shutdown ─────────────────────────────────────────────────

    public Map<String, Object> health() {
        return Map.of(
                "status", "UP",
                "apiPort", config.internalApiPort(),
                "profiles", profiles.size(),
                "modpackCompatibility", modpackCompatibilityMode.name(),
                "timestamp", Instant.now().toString()
        );
    }

    public ModpackCompatibilityMode getModpackCompatibilityMode() {
        return modpackCompatibilityMode;
    }

    public ModpackCompatibilityMode setModpackCompatibilityMode(ModpackCompatibilityMode mode) {
        if (mode == null) {
            throw new IllegalArgumentException("mode es obligatorio");
        }
        this.modpackCompatibilityMode = mode;
        return this.modpackCompatibilityMode;
    }

    public String getProfileInstancePath(String profileId) {
        MinecraftProfile profile = Optional.ofNullable(profiles.get(profileId))
                .orElseThrow(() -> new IllegalArgumentException("Perfil no encontrado: " + profileId));
        return ensureProfileInstanceDirectory(profile).toAbsolutePath().toString();
    }

    public void shutdown() {
        downloadTasks.values().forEach(t -> t.cancel(false));
        scheduler.shutdownNow();
        activeProcesses.values().forEach(Process::destroy);
    }

    // ── Utilidades ────────────────────────────────────────────────────────

    private boolean isVersionInstalled(String version) {
        Path dir  = config.gameDirectory().resolve("versions").resolve(version);
        Path jar  = dir.resolve(version + ".jar");
        Path json = dir.resolve(version + ".json");
        try {
            return Files.exists(json) && Files.exists(jar) && Files.size(jar) > 10_000;
        } catch (IOException e) { return false; }
    }

    private boolean isTerminal(String state) {
        return "DONE".equals(state) || "FAILED".equals(state);
    }

    private String extractUsername(MinecraftProfile profile) {
        List<String> args = profile.gameArgs();
        for (int i = 0; i < args.size() - 1; i++) {
            if ("--username".equals(args.get(i))) return args.get(i + 1);
        }
        // Fallback: usar el nombre del perfil sin espacios
        return profile.displayName().replaceAll("\\s+", "_");
    }

    private void runPreparedLaunch(String operationId, LaunchRequest request, MinecraftProfile profile) {
        try {
            LaunchPlan basePlan = resolveLaunchPlan(profile);
            Path instanceDir = profileGameDirectory(profile);
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    1,
                    "Verificando instalacion de Minecraft " + basePlan.minecraftVersion() + "..."
            ));

            versionDownloader.downloadVersion(basePlan.minecraftVersion(), instanceDir, (progress, message) -> {
                int mappedProgress = Math.max(1, Math.min(60, progress * 60 / 100));
                String safeMessage = (message == null || message.isBlank())
                        ? "Preparando archivos de Minecraft..."
                        : message;
                preparedLaunches.put(operationId, new PreparedLaunchStatus(
                        operationId,
                        profile.id(),
                        basePlan.minecraftVersion(),
                        "PREPARING",
                        mappedProgress,
                        safeMessage
                ));
            });

            LaunchPlan readyPlan = prepareLoadersAndModpack(operationId, profile, basePlan, instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "STARTING",
                    95,
                    "Iniciando Minecraft..."
            ));

            LaunchResult result = launchWithVersion(request, profile, readyPlan.effectiveVersionId(), instanceDir);

            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    readyPlan.effectiveVersionId(),
                    "DONE",
                    100,
                    "Minecraft iniciado.",
                    result.launchId()
            ));
        } catch (Exception ex) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    profile.gameVersion(),
                    "FAILED",
                    0,
                    "Error: " + ex.getMessage()
            ));
        }
    }

    private LaunchPlan prepareLoadersAndModpack(String operationId, MinecraftProfile profile,
                                                LaunchPlan basePlan, Path gameDir)
            throws IOException, InterruptedException {
        String effectiveVersion = basePlan.minecraftVersion();

        if (basePlan.hasLoader()) {
            preparedLaunches.put(operationId, new PreparedLaunchStatus(
                    operationId,
                    profile.id(),
                    basePlan.minecraftVersion(),
                    "PREPARING",
                    62,
                    "Instalando loader " + basePlan.loaderType() + " " + basePlan.loaderVersion() + "..."
            ));

            effectiveVersion = modpackInstaller.installLoader(
                    basePlan.loaderType(),
                    basePlan.minecraftVersion(),
                    basePlan.loaderVersion(),
                    gameDir,
                    (progress, message) -> preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            basePlan.minecraftVersion(),
                            "PREPARING",
                            60 + Math.max(0, Math.min(progress, 100)) * 25 / 100,
                            message == null || message.isBlank() ? "Instalando loader..." : message
                    ))
            );
        }

        if (basePlan.hasModpack()) {
            Path modpackPath = basePlan.modpackPath();
            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            String launchVersion = effectiveVersion;
            modpackInstaller.installModpackFiles(modpackPath, manifest, gameDir, (progress, message) ->
                    preparedLaunches.put(operationId, new PreparedLaunchStatus(
                            operationId,
                            profile.id(),
                            launchVersion,
                            "PREPARING",
                            85 + Math.max(0, Math.min(progress, 100)) * 10 / 100,
                            message == null || message.isBlank() ? "Instalando modpack..." : message
                    ))
            );
        }

        return new LaunchPlan(
                basePlan.minecraftVersion(),
                basePlan.loaderType(),
                basePlan.loaderVersion(),
                basePlan.modpackPath(),
                effectiveVersion
        );
    }

    private LaunchPlan prepareProfile(MinecraftProfile profile, Path gameDir, BiConsumer<Integer, String> progress)
            throws IOException, InterruptedException {
        LaunchPlan plan = resolveLaunchPlan(profile);

        progress.accept(0, "Preparando Minecraft " + plan.minecraftVersion() + "...");
        versionDownloader.downloadVersion(plan.minecraftVersion(), gameDir, progress);

        String effectiveVersion = plan.minecraftVersion();
        if (plan.hasLoader()) {
            effectiveVersion = modpackInstaller.installLoader(
                    plan.loaderType(),
                    plan.minecraftVersion(),
                    plan.loaderVersion(),
                    gameDir,
                    progress
            );
        }

        if (plan.hasModpack()) {
            ModpackManifest manifest = parseAndValidateModpack(plan.modpackPath());
            modpackInstaller.installModpackFiles(plan.modpackPath(), manifest, gameDir, progress);
        }

        return new LaunchPlan(plan.minecraftVersion(), plan.loaderType(), plan.loaderVersion(), plan.modpackPath(), effectiveVersion);
    }

    private LaunchPlan resolveLaunchPlan(MinecraftProfile profile) throws IOException {
        String minecraftVersion = profile.gameVersion();
        String loaderType = profile.loaderType();
        String loaderVersion = profile.loaderVersion();
        Path modpackPath = null;

        if (profile.hasModpack()) {
            modpackPath = Path.of(profile.modpackPath());
            if (!Files.exists(modpackPath)) {
                throw new IOException("No existe el modpack en ruta: " + modpackPath);
            }

            ModpackManifest manifest = parseAndValidateModpack(modpackPath);
            if (manifest.minecraftVersion() != null && !manifest.minecraftVersion().isBlank()) {
                minecraftVersion = manifest.minecraftVersion();
            }
            if (manifest.loaderType() != null && !manifest.loaderType().isBlank()) {
                loaderType = manifest.loaderType();
            }
            if (manifest.loaderVersion() != null && !manifest.loaderVersion().isBlank()) {
                loaderVersion = manifest.loaderVersion();
            }
        }

        String effectiveVersion = ModpackInstaller.computeEffectiveVersionId(
                minecraftVersion,
                loaderType,
                loaderVersion
        );

        return new LaunchPlan(minecraftVersion, loaderType, loaderVersion, modpackPath, effectiveVersion);
    }

    private ModpackManifest parseAndValidateModpack(Path modpackPath) throws IOException {
        ModpackManifest manifest = modpackInstaller.parseModpack(modpackPath);
        if (!modpackCompatibilityMode.isAllowed(manifest.source())) {
            throw new IOException("Formato de modpack no permitido por compatibilidad actual ("
                    + modpackCompatibilityMode + "): " + manifest.source());
        }
        return manifest;
    }

    private Path profileGameDirectory(MinecraftProfile profile) {
        String safeId = profile.id().replaceAll("[^a-zA-Z0-9._-]", "_");
        return config.gameDirectory().resolve("instances").resolve(safeId);
    }

    private Path ensureProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        try {
            Files.createDirectories(instanceDir);
            return instanceDir;
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo preparar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void deleteProfileInstanceDirectory(MinecraftProfile profile) {
        Path instanceDir = profileGameDirectory(profile);
        if (!Files.exists(instanceDir)) {
            return;
        }
        try (java.util.stream.Stream<Path> walk = Files.walk(instanceDir)) {
            walk.sorted(Comparator.reverseOrder()).forEach(path -> {
                try {
                    Files.deleteIfExists(path);
                } catch (IOException ex) {
                    throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
                }
            });
        } catch (IOException ex) {
            throw new IllegalStateException("No se pudo eliminar la instancia del perfil " + profile.id(), ex);
        }
    }

    private void stopActiveProcessesForProfile(String profileId) {
        activeProcessProfiles.entrySet().stream()
                .filter(entry -> profileId.equals(entry.getValue()))
                .map(Map.Entry::getKey)
                .forEach(this::stopProcessByLaunchId);
    }

    private void stopProcessByLaunchId(String launchId) {
        Process process = activeProcesses.get(launchId);
        if (process == null) {
            activeProcessProfiles.remove(launchId);
            return;
        }

        try {
            process.destroy();
            if (!process.waitFor(2, TimeUnit.SECONDS)) {
                process.destroyForcibly();
                process.waitFor(2, TimeUnit.SECONDS);
            }
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
        } finally {
            activeProcesses.remove(launchId);
            activeProcessProfiles.remove(launchId);
        }
    }

    private record LaunchPlan(
            String minecraftVersion,
            String loaderType,
            String loaderVersion,
            Path modpackPath,
            String effectiveVersionId
    ) {
        private boolean hasLoader() {
            return loaderType != null && !loaderType.isBlank() && !"VANILLA".equalsIgnoreCase(loaderType);
        }

        private boolean hasModpack() {
            return modpackPath != null;
        }
    }
}

