            Path instanceA = Path.of(service.getProfileInstancePath("forge-a"));
            Path instanceB = Path.of(service.getProfileInstancePath("forge-b"));

            assertTrue(Files.isDirectory(instanceA));
            assertTrue(Files.isDirectory(instanceB));
            assertTrue(instanceA.endsWith(Path.of("instances", "forge-a")));
            assertTrue(instanceB.endsWith(Path.of("instances", "forge-b")));
            assertTrue(!instanceA.equals(instanceB));
        } finally {
            service.shutdown();
        }
    }

    @Test
    void shouldDeleteProfileAndInstanceDirectory() throws IOException {
        LauncherConfig config = new LauncherConfig(
                tempDir,
                tempDir.resolve("profiles.json"),
                tempDir.resolve("game"),
                7878,
                "1.0-SNAPSHOT",
                ""
        );
        LauncherService service = new LauncherService(
                config,
                new ProfileStore(config.profilesFile(), new ObjectMapper())
        );

        try {
            MinecraftProfile profile = new MinecraftProfile(
                    "to-delete", "Eliminar", "java", "1.20.1",
                    List.of("-Xmx2G"), List.of("--username", "Alex"),
                    "VANILLA", "", ""
            );
            service.createProfile(profile);

            Path instanceDir = Path.of(service.getProfileInstancePath("to-delete"));
            Files.createDirectories(instanceDir.resolve("mods"));
            Files.writeString(instanceDir.resolve("mods").resolve("keep.txt"), "x");

            MinecraftProfile deleted = service.deleteProfile("to-delete");

            assertEquals("to-delete", deleted.id());
            assertEquals(0, service.listProfiles().size());
            assertTrue(Files.notExists(instanceDir));
        } finally {
            service.shutdown();
        }
    }

    @Test
    void shouldAcceptCurseForgeModpackWhenCompatibilityIsBoth() throws IOException {
        LauncherConfig config = new LauncherConfig(
                tempDir,
                tempDir.resolve("profiles.json"),
                tempDir.resolve("game"),
                7878,
                "1.0-SNAPSHOT",
                ""
        );
        Path modpack = createCurseManifestZip(tempDir.resolve("cf-pack.zip"));

        LauncherService service = new LauncherService(
                config,
                new ProfileStore(config.profilesFile(), new ObjectMapper()),
                fakeDownloader(),
                new ModpackInstaller(),
                ModpackCompatibilityMode.BOTH
        );

        try {
            MinecraftProfile profile = new MinecraftProfile(
                    "cf", "Curse Pack", "java", "1.20.1",
                    List.of("-Xmx1G"), List.of("--username", "Alex"),
                    "VANILLA", "", modpack.toAbsolutePath().toString()
            );
            service.createProfile(profile);

            assertNotNull(service.launch(new LaunchRequest("cf", false)).launchId());
        } finally {
            service.shutdown();
        }
    }

    @Test
    void shouldRejectCurseForgeModpackWhenCompatibilityIsModrinthOnly() throws IOException {
        LauncherConfig config = new LauncherConfig(
                tempDir,
                tempDir.resolve("profiles.json"),
                tempDir.resolve("game"),
                7878,
                "0.5-SNAPSHOT",
                ""
        );
        Path modpack = createCurseManifestZip(tempDir.resolve("cf-blocked.zip"));

        LauncherService service = new LauncherService(
                config,
                new ProfileStore(config.profilesFile(), new ObjectMapper()),
                fakeDownloader(),
                new ModpackInstaller(),
                ModpackCompatibilityMode.MODRINTH_ONLY
        );

        try {
            MinecraftProfile profile = new MinecraftProfile(
                    "cf-blocked", "Curse Pack", "java", "1.20.1",
                    List.of("-Xmx1G"), List.of("--username", "Alex"),
                    "VANILLA", "", modpack.toAbsolutePath().toString()
            );
            service.createProfile(profile);

            IllegalStateException ex = assertThrows(IllegalStateException.class,
                    () -> service.launch(new LaunchRequest("cf-blocked", false)));
            assertTrue(ex.getMessage().contains("Formato de modpack no permitido"));
        } finally {
            service.shutdown();
        }
    }

    private Path createCurseManifestZip(Path zipPath) throws IOException {
        String manifest = """
                {
                  "minecraft": { "version": "1.20.1", "modLoaders": [] },
                  "name": "CF Test",
                  "version": "1.0.0",
                  "files": []
                }
                """;
        try (OutputStream out = Files.newOutputStream(zipPath);
             ZipOutputStream zip = new ZipOutputStream(out)) {
            zip.putNextEntry(new ZipEntry("manifest.json"));
            zip.write(manifest.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            zip.closeEntry();
        }
        return zipPath;
    }

    private boolean startsWithJarMagic(Path file) {
        try {
            byte[] header = Files.readAllBytes(file);
            return header.length >= 4
                    && header[0] == 'P'
                    && header[1] == 'K'
                    && header[2] == 3
                    && header[3] == 4;
        } catch (IOException ex) {
            return false;
        }
    }
}
